import React from 'react';
import { SpotterEmbed, useEmbedRef } from '@thoughtspot/visual-embed-sdk/react';
import { HostEvent } from '@thoughtspot/visual-embed-sdk';
import './config/thoughtspot';
import './App.css';
import WordCloud from './WordCloud';

export default function App() {
  const embedRef = useEmbedRef();

  const handleQuestionSelect = (query) => {
    if (embedRef.current) {
      embedRef.current.trigger(HostEvent.SpotterSearch, {
        query,
        executeSearch: true,
      });
    }
  };

  return (
    <div className="app">
      <div className="bg" />
      <div className="grid-lines" />

      {/* Header */}
      <header className="header">
        <div className="header-left">
          <img src="/thoughtspot_logo.jpeg" alt="ThoughtSpot" className="ts-logo-img" />
          <span className="ts-wordmark">Thought<span>Spot</span></span>
        </div>
        <div className="header-right">
        </div>
      </header>

      {/* Hero */}
      <section className="hero">
        <div className="event-pill">
          <span className="event-pill-dot" />
          Data Innovation Summit 2026
        </div>
        <div className="event-pill-sub">
          6–8 May · Kistamässan, Stockholm · DIS2026X1
        </div>
        <h1 className="hero-title">
          Ask <span className="highlight">anything</span><br />about data &amp; AI
        </h1>
        <p className="hero-subtitle">
          Powered by ThoughtSpot Spotter — your AI analyst for the
          Data Innovation Summit. Ask questions, explore insights, and discover
          what's shaping the future of data.
        </p>
      </section>

      {/* Spotter + word clouds side by side */}
      <div className="spotter-layout">
        <WordCloud onSelect={handleQuestionSelect} />

        <div className="spotter-wrapper">
          <div className="spotter-glow" />
          <div className="spotter-card">
            <div className="spotter-embed-area">
              <SpotterEmbed
                ref={embedRef}
                worksheetId="acdd8a7c-975a-4664-81a4-e715df113864"
                frameParams={{ height: '700px', width: '100%' }}
                hideSampleQuestions={false}
                disableSourceSelection={true}
                onError={(e) => console.error('Spotter error:', e)}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Event stats strip */}
      <div className="event-strip">
        <div className="strip-item">
          <span className="strip-value">3,500+</span>
          <span className="strip-label">Delegates</span>
        </div>
        <div className="strip-sep" />
        <div className="strip-item">
          <span className="strip-value">300+</span>
          <span className="strip-label">Speakers</span>
        </div>
        <div className="strip-sep" />
        <div className="strip-item">
          <span className="strip-value">15</span>
          <span className="strip-label">Stages</span>
        </div>
        <div className="strip-sep" />
        <div className="strip-item">
          <span className="strip-value">3 Days</span>
          <span className="strip-label">6–8 May 2026</span>
        </div>
        <div className="strip-sep" />
        <div className="strip-item">
          <span className="strip-value">100+</span>
          <span className="strip-label">Exhibitors</span>
        </div>
      </div>

      {/* Footer */}
      <footer className="footer">
        Powered by <a href="https://www.thoughtspot.com/product/agents" target="_blank" rel="noopener noreferrer">ThoughtSpot Spotter</a>
        &nbsp;·&nbsp;
        <a href="https://datainnovationsummit.com/region/nordics/" target="_blank" rel="noopener noreferrer">Data Innovation Summit 2026</a>
      </footer>
    </div>
  );
}
